
.panel {
  width: 100%;
  border: 1px solid #c0c0c0;
  font-size: 13px;
  line-height: 1.4;
  color: #333;
  margin: 0 auto;
}

.header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  cursor: pointer;
  user-select: none;

  &:hover { background: rgba(0, 0, 0, 0.03); }

  .fa {
    font-size: 12px;
    width: 14px;
  }

  .header-title { font-weight: 600; }
}

.tabs {
  display: flex;
  background: #f5f5f5;
  border-top: 1px solid #c0c0c0;
  border-bottom: 1px solid #c0c0c0;

  button {
    flex: 1;
    padding: 6px 0;
    border: none;
    background: none;
    font-size: 13px;
    cursor: pointer;
    color: #666;

    &.active {
      color: #333;
      font-weight: 600;
      background: #fff;
      border-bottom: 2px solid #c00000;
    }

    &:hover:not(.active) { background: rgba(0, 0, 0, 0.04); }
  }
}

.tab-body {
  padding: 8px 12px;
}

.pane {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.empty {
  text-align: center;
  color: #999;
  padding: 12px 0;
}

.card {
  border: 1px solid #e0e0e0;
  padding: 6px 10px;
}

.card-head {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 4px;

  .name { font-weight: 600; }
  .level { font-size: 11px; color: #666; margin-left: auto; }
}

.tag {
  font-size: 11px;
  padding: 0 5px;

  &.rating {
    background: #fff3cd;
    color: #856404;
  }

  &.type {
    color: #fff;
    &.母猪 { background: #e91e63; }
    &.母牛 { background: #795548; }
    &.母狗 { background: #ff9800; }
  }
}

.kv {
  display: flex;
  justify-content: space-between;
  padding: 3px 0;
  border-bottom: 1px solid #f0f0f0;

  &:last-child { border-bottom: none; }

  small {
    color: #999;
    font-size: 11px;
    margin-left: 4px;
  }

  &.dim { opacity: 0.4; }
}

.stat-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 4px;
  padding: 4px 0;

  .stat {
    text-align: center;

    label {
      display: block;
      font-size: 10px;
      color: #888;
    }

    span {
      font-size: 13px;
      font-weight: 500;
    }
  }
}

.section {
  .section-title {
    font-weight: 600;
    font-size: 12px;
    margin-bottom: 4px;
    padding-bottom: 4px;
    border-bottom: 1px solid #ddd;

    .fa { margin-right: 4px; }
  }

  & + & { margin-top: 10px; }
}
